147→function isToolPart(part: { type: string }): boolean {
148→  return part.type.startsWith("tool-");
149→}
150→
151→function ChatInput({
152→  onSend,
153→  disabled,
154→  onStop,
155→  isStreaming,
156→}: {
157→  onSend: (text: string) => void;
158→  disabled: boolean;
159→  onStop: () => void;
160→  isStreaming: boolean;
161→}) {
162→  const [input, setInput] = useState("");
163→  const textareaRef = useRef<HTMLTextAreaElement>(null);
164→
165→  function handleSubmit() {
166→    const trimmed = input.trim();
167→    if (!trimmed || disabled) return;
168→    onSend(trimmed);
169→    setInput("");
170→    // Reset textarea height
171→    if (textareaRef.current) {
172→      textareaRef.current.style.height = "auto";
173→    }
174→  }
175→
176→  function handleKeyDown(e: KeyboardEvent<HTMLTextAreaElement>) {
177→    if (e.key === "Enter" && !e.shiftKey) {
178→      e.preventDefault();
179→      handleSubmit();
180→    }
181→  }
182→
183→  // Auto-resize textarea
184→  useEffect(() => {
185→    const textarea = textareaRef.current;
186→    if (!textarea) return;
187→    textarea.style.height = "auto";
188→    textarea.style.height = `${Math.min(textarea.scrollHeight, 200)}px`;
189→  }, [input]);
190→
191→  return (
192→    <div className="chat-input-container">
193→      <textarea
194→        ref={textareaRef}
195→        className="chat-input"
196→        value={input}
197→        onChange={(e) => setInput(e.target.value)}
198→        onKeyDown={handleKeyDown}
199→        placeholder="Discuss tasks, decisions, and questions..."
200→        rows={1}
201→        disabled={disabled && !isStreaming}
202→      />
203→      {isStreaming ? (
204→        <button
205→          type="button"
206→          className="chat-input-btn chat-input-btn--stop"
207→          onClick={onStop}
208→          title="Stop"
209→        >
210→          Stop
211→        </button>
212→      ) : (
213→        <button
214→          type="button"
215→          className="chat-input-btn chat-input-btn--send"
216→          onClick={handleSubmit}
217→          disabled={disabled || input.trim().length === 0}
218→          title="Send"
219→        >
220→          Send
221→        </button>
222→      )}
223→    </div>
224→  );
225→}
