357→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
358→  LET $query = string::lowercase(string::trim($q));
359→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
360→
361→  LET $task_rows = SELECT
362→    id,
363→    "task" AS kind,
364→    title AS text,
365→    extraction_confidence AS confidence,
366→    source_message AS sourceMessage,
367→    priority,
368→    created_at
369→  FROM task
370→  WHERE workspace = $workspace
371→    AND extraction_confidence != NONE
372→    AND string::contains(string::lowercase(title), $query)
373→  ORDER BY created_at DESC
374→  LIMIT $safe_limit;
375→
376→  LET $decision_rows = SELECT
377→    id,
378→    "decision" AS kind,
379→    summary AS text,
380→    extraction_confidence AS confidence,
381→    source_message AS sourceMessage,
382→    priority,
383→    created_at
384→  FROM decision
385→  WHERE workspace = $workspace
386→    AND extraction_confidence != NONE
387→    AND string::contains(string::lowercase(summary), $query)
388→  ORDER BY created_at DESC
389→  LIMIT $safe_limit;
390→
391→  LET $question_rows = SELECT
392→    id,
393→    "question" AS kind,
394→    text AS text,
395→    extraction_confidence AS confidence,
396→    source_message AS sourceMessage,
397→    priority,
398→    created_at
399→  FROM question
400→  WHERE workspace = $workspace
401→    AND extraction_confidence != NONE
402→    AND string::contains(string::lowercase(text), $query)
403→  ORDER BY created_at DESC
404→  LIMIT $safe_limit;
405→
406→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
407→};
