  1→import { stepCountIs, streamText, type ModelMessage } from "ai";
  2→import { RecordId, Surreal } from "surrealdb";
  3→import type { ExtractedEntity, ExtractedRelationship, OnboardingState } from "../../shared/contracts";
  4→import { logInfo, logError } from "../http/observability";
  5→import { buildChatContext, buildSystemPrompt, type ChatContext } from "./context";
  6→import { createChatAgentTools } from "./tools";
  7→
  8→type ConversationMessage = {
  9→  role: "user" | "assistant";
 10→  text: string;
 11→};
 12→
 13→type CollectedEntity = ExtractedEntity;
 14→type CollectedRelationship = ExtractedRelationship;
 15→
 16→export type ChatAgentResult = {
 17→  text: string;
 18→  collectedEntities: CollectedEntity[];
 19→  collectedRelationships: CollectedRelationship[];
 20→};
 21→
 22→export async function runChatAgent(input: {
 23→  surreal: Surreal;
 24→  model: any;
 25→  pmAgentModel: any;
 26→  analyticsAgentModel: any;
 27→  analyticsSurreal: Surreal;
 28→  embeddingModel: any;
 29→  embeddingDimension: number;
 30→  extractionModelId: string;
 31→  extractionModel: any;
 32→  extractionStoreThreshold: number;
 33→  conversationRecord: RecordId<"conversation", string>;
 34→  workspaceRecord: RecordId<"workspace", string>;
 35→  currentMessageRecord: RecordId<"message", string>;
 36→  latestUserText: string;
 37→  workspaceOwnerRecord?: RecordId<"person", string>;
 38→  userMessageEmbedding?: number[];
 39→  inheritedEntityIds?: RecordId[];
 40→  discussesRecord?: RecordId;
 41→  messages: ConversationMessage[];
 42→  isOnboarding?: boolean;
 43→  onboardingState?: OnboardingState;
 44→  onToken: (token: string) => Promise<void> | void;
 45→  onReasoning?: (token: string) => Promise<void> | void;
 46→}): Promise<ChatAgentResult> {
 47→  const context = await buildChatContext({
 48→    surreal: input.surreal,
 49→    conversationRecord: input.conversationRecord,
 50→    workspaceRecord: input.workspaceRecord,
 51→    ...(input.userMessageEmbedding ? { userMessageEmbedding: input.userMessageEmbedding } : {}),
 52→    ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 53→      ? { inheritedEntityIds: input.inheritedEntityIds }
 54→      : {}),
 55→    ...(input.discussesRecord ? { discussesRecord: input.discussesRecord } : {}),
 56→  });
 57→
 58→  const system = buildSystemPrompt(context, {
 59→    isOnboarding: input.isOnboarding,
 60→    onboardingState: input.onboardingState,
 61→  });
 62→
 63→  const modelMessages: ModelMessage[] = input.messages.map((message) => ({
 64→    role: message.role,
 65→    content: message.text,
 66→  }));
 67→
 68→  const result = streamText({
 69→    model: input.model,
 70→    system,
 71→    messages: modelMessages,
 72→    tools: createChatAgentTools({
 73→      surreal: input.surreal,
 74→      pmAgentModel: input.pmAgentModel,
 75→      analyticsAgentModel: input.analyticsAgentModel,
 76→      analyticsSurreal: input.analyticsSurreal,
 77→      embeddingModel: input.embeddingModel,
 78→      embeddingDimension: input.embeddingDimension,
 79→      extractionModelId: input.extractionModelId,
 80→      extractionModel: input.extractionModel,
 81→      extractionStoreThreshold: input.extractionStoreThreshold,
 82→    }),
 83→    experimental_context: {
 84→      actor: "chat_agent",
 85→      workspaceRecord: input.workspaceRecord,
 86→      conversationRecord: input.conversationRecord,
 87→      currentMessageRecord: input.currentMessageRecord,
 88→      latestUserText: input.latestUserText,
 89→      ...(input.workspaceOwnerRecord ? { workspaceOwnerRecord: input.workspaceOwnerRecord } : {}),
 90→    },
 91→    stopWhen: stepCountIs(5),
 92→  });
 93→
 94→  let text = "";
 95→  const collectedEntities: CollectedEntity[] = [];
 96→  const collectedRelationships: CollectedRelationship[] = [];
 97→
 98→  for await (const part of result.fullStream) {
 99→    if (part.type === "reasoning-delta") {
100→      await input.onReasoning?.(part.text);
101→      continue;
102→    }
103→
104→    if (part.type === "text-delta") {
105→      text = `${text}${part.text}`;
106→      await input.onToken(part.text);
107→      continue;
108→    }
109→
110→    if (part.type === "tool-call") {
111→      logInfo("chat.agent.tool_call", "Chat agent invoked tool", part);
112→    }
113→
114→    if (part.type === "tool-result") {
115→      logInfo("chat.agent.tool_result", "Chat agent tool returned", part);
116→      const toolResult = part.output as Record<string, unknown> | undefined;
117→      if (toolResult) {
118→        if (Array.isArray(toolResult.extracted_entities)) {
119→          collectedEntities.push(...(toolResult.extracted_entities as CollectedEntity[]));
120→        }
121→        if (Array.isArray(toolResult.extracted_relationships)) {
122→          collectedRelationships.push(...(toolResult.extracted_relationships as CollectedRelationship[]));
123→        }
124→      }
125→    }
126→
127→    if (part.type === "error") {
128→      logError("chat.agent.stream_error", "Chat agent stream error", part.error, {});
129→    }
130→  }
131→
132→  if (text.trim().length === 0) {
133→    text = await result.text;
134→  }
135→
136→  // Post-process: inject entity:// links for entity names mentioned in the response.
137→  const linked = injectEntityLinks(text, context);
138→  if (linked !== text) {
139→    // Re-send the full linked text as a replacement.
140→    // The SSE stream already sent raw text; the persisted version will have links.
141→    text = linked;
142→  }
143→
144→  return {
145→    text: text.trim(),
146→    collectedEntities,
147→    collectedRelationships,
148→  };
149→}
