151→export const runGraphAwareChat = runChatAgent;
152→
153→type KnownEntity = { entityId: string; kind: string; name: string };
154→
155→/**
156→ * Replace entity name mentions in response text with markdown links:
157→ *   "Model for Extraction Pipeline" → "[Model for Extraction Pipeline](entity://decision:uuid)"
158→ *
159→ * Matches longest names first to avoid partial replacement.
160→ * Only replaces the first occurrence of each entity name.
161→ */
162→function injectEntityLinks(text: string, context: ChatContext): string {
163→  const entities: KnownEntity[] = [];
164→
165→  for (const project of context.workspaceSummary.projects) {
166→    entities.push({ entityId: `project:${project.id}`, kind: "project", name: project.name });
167→  }
168→  for (const decision of context.workspaceSummary.recentDecisions) {
169→    entities.push({ entityId: `decision:${decision.id}`, kind: "decision", name: decision.name });
170→  }
171→  for (const question of context.workspaceSummary.openQuestions) {
172→    entities.push({ entityId: `question:${question.id}`, kind: "question", name: question.name });
173→  }
174→
175→  // Sort longest name first so "Agent-Native Business OS" matches before "Agent"
176→  entities.sort((a, b) => b.name.length - a.name.length);
177→
178→  const replaced = new Set<string>();
179→  let result = text;
180→
181→  for (const entity of entities) {
182→    if (entity.name.length < 3) continue;
183→    if (replaced.has(entity.entityId)) continue;
184→
185→    // Case-insensitive match, but only replace the first occurrence.
186→    // Skip if the name is already inside a markdown link.
187→    const idx = result.toLowerCase().indexOf(entity.name.toLowerCase());
188→    if (idx === -1) continue;
189→
190→    // Check if already inside a markdown link: [...](...)
191→    const before = result.slice(0, idx);
192→    if (before.lastIndexOf("[") > before.lastIndexOf("]")) continue;
193→
194→    const matched = result.slice(idx, idx + entity.name.length);
195→    const link = `[${matched}](#entity/${entity.entityId})`;
196→    result = `${result.slice(0, idx)}${link}${result.slice(idx + entity.name.length)}`;
197→    replaced.add(entity.entityId);
198→  }
199→
200→  return result;
201→}
