  1→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
  2→import { useChat, type UseChatHelpers } from "@ai-sdk/react";
  3→import { DefaultChatTransport, type UIMessage } from "ai";
  4→import type {
  5→  BranchConversationResponse,
  6→  DiscussEntitySummary,
  7→  OnboardingAction,
  8→  OnboardingState,
  9→  WorkspaceBootstrapMessage,
 10→  WorkspaceConversationResponse,
 11→} from "../../shared/contracts";
 12→import { useWorkspaceState, type BootstrapPayload } from "../stores/workspace-state";
 13→import { useViewState } from "../stores/view-state";
 14→
 15→type ChatMessageMetadata = {
 16→  onboardingState?: OnboardingState;
 17→  conversationId?: string;
 18→};
 19→
 20→type ChatUIMessage = UIMessage<ChatMessageMetadata>;
 21→
 22→export type UseChatSessionReturn = {
 23→  messages: ChatUIMessage[];
 24→  status: UseChatHelpers<ChatUIMessage>["status"];
 25→  isLoading: boolean;
 26→  errorMessage?: string;
 27→  activeConversationId?: string;
 28→  branchingFromId?: string;
 29→  discussEntity?: DiscussEntitySummary;
 30→  conversationDiscussEntity?: DiscussEntitySummary;
 31→  sendMessage: (text: string, options?: { onboardingAction?: OnboardingAction }) => void;
 32→  stopMessage: () => void;
 33→  newConversation: () => void;
 34→  selectConversation: (conversationId: string) => void;
 35→  branchFromMessage: (messageId: string) => Promise<void>;
 36→  setErrorMessage: (message: string | undefined) => void;
 37→  refreshSidebar: (workspaceId: string) => Promise<void>;
 38→};
 39→
 40→function bootstrapMessagesToUIMessages(messages: WorkspaceBootstrapMessage[]): ChatUIMessage[] {
 41→  return messages.map((m) => ({
 42→    id: m.id,
 43→    role: m.role,
 44→    parts: [{ type: "text" as const, text: m.text }],
 45→    createdAt: new Date(m.createdAt),
 46→  }));
 47→}
 48→
 49→export function useChatSession(): UseChatSessionReturn {
 50→  const store = useWorkspaceState();
 51→  const workspaceId = store.workspaceId;
 52→  const bootstrapPayload = store.bootstrapPayload;
 53→
 54→  const [activeConversationId, setActiveConversationId] = useState<string | undefined>();
 55→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 56→  const [branchingFromId, setBranchingFromId] = useState<string | undefined>();
 57→  const [conversationDiscussEntity, setConversationDiscussEntity] = useState<
 58→    DiscussEntitySummary | undefined
 59→  >();
 60→
 61→  const discussEntity = useViewState((s) => s.discussEntity);
 62→  const clearDiscussEntity = useViewState((s) => s.clearDiscussEntity);
 63→
 64→  // Dynamic body refs — these are read by the transport body function
 65→  const conversationIdRef = useRef<string | undefined>(undefined);
 66→  const onboardingActionRef = useRef<OnboardingAction | undefined>(undefined);
 67→  const discussEntityIdRef = useRef<string | undefined>(undefined);
 68→
 69→  // Keep conversationId ref in sync
 70→  useEffect(() => {
 71→    conversationIdRef.current = activeConversationId;
 72→  }, [activeConversationId]);
 73→
 74→  // Keep discuss entity ref in sync
 75→  useEffect(() => {
 76→    discussEntityIdRef.current = discussEntity?.id;
 77→  }, [discussEntity]);
 78→
 79→  const transport = useMemo(
 80→    () =>
 81→      new DefaultChatTransport({
 82→        api: "/api/chat",
 83→        body: () => ({
 84→          workspaceId,
 85→          ...(conversationIdRef.current ? { conversationId: conversationIdRef.current } : {}),
 86→          ...(onboardingActionRef.current
 87→            ? { onboardingAction: onboardingActionRef.current }
 88→            : {}),
 89→          ...(discussEntityIdRef.current
 90→            ? { discussEntityId: discussEntityIdRef.current }
 91→            : {}),
 92→        }),
 93→      }),
 94→    [workspaceId],
 95→  );
 96→
 97→  const chat = useChat<ChatUIMessage>({
 98→    transport,
 99→    onFinish: ({ message }) => {
100→      const metadata = message.metadata;
101→      if (metadata?.conversationId && !conversationIdRef.current) {
102→        setActiveConversationId(metadata.conversationId);
103→        conversationIdRef.current = metadata.conversationId;
104→        if (discussEntity) {
105→          clearDiscussEntity();
106→        }
107→      }
108→      if (metadata?.onboardingState) {
109→        store.setOnboardingState(metadata.onboardingState);
110→      }
111→
112→      // Refresh sidebar
113→      if (workspaceId) {
114→        void refreshSidebar(workspaceId);
115→      }
116→    },
117→    onError: (error) => {
118→      setErrorMessage(error.message);
119→    },
120→  });
121→
122→  const isLoading = chat.status === "streaming" || chat.status === "submitted";
123→
124→  // Apply bootstrap payload when it arrives
125→  const appliedBootstrapRef = useRef<BootstrapPayload | undefined>(undefined);
126→  useEffect(() => {
127→    if (!bootstrapPayload || bootstrapPayload === appliedBootstrapRef.current) {
128→      return;
129→    }
130→    appliedBootstrapRef.current = bootstrapPayload;
131→
132→    chat.setMessages(bootstrapPayload.messages as ChatUIMessage[]);
133→    setActiveConversationId(store.conversationId);
134→    conversationIdRef.current = store.conversationId;
135→  }, [bootstrapPayload]);
136→
137→  // Highlight message support (graph -> chat navigation)
138→  const highlightMessageId = useViewState((s) => s.highlightMessageId);
139→  const clearHighlight = useViewState((s) => s.clearHighlight);
140→
141→  useEffect(() => {
142→    if (!highlightMessageId) return;
143→
144→    const timer = setTimeout(() => {
145→      const element = document.querySelector(`[data-message-id="${highlightMessageId}"]`);
146→      if (element) {
147→        element.scrollIntoView({ behavior: "smooth", block: "center" });
148→        element.classList.add("animate-highlight");
149→        element.addEventListener(
150→          "animationend",
151→          () => {
152→            element.classList.remove("animate-highlight");
153→          },
154→          { once: true },
155→        );
156→      }
157→      clearHighlight();
158→    }, 100);
159→
160→    return () => clearTimeout(timer);
161→  }, [highlightMessageId, clearHighlight]);
162→
163→  async function refreshSidebar(wsId: string) {
164→    try {
165→      const response = await fetch(`/api/workspaces/${encodeURIComponent(wsId)}/sidebar`);
166→      if (response.ok) {
167→        const payload = await response.json();
168→        store.setSidebar(payload);
169→      }
170→    } catch {
171→      // Sidebar refresh is non-critical
172→    }
173→  }
174→
175→  async function loadConversation(wsId: string, conversationId: string) {
176→    try {
177→      const response = await fetch(
178→        `/api/workspaces/${encodeURIComponent(wsId)}/conversations/${encodeURIComponent(conversationId)}`,
179→      );
180→      if (!response.ok) {
181→        const body = await response.text();
182→        setErrorMessage(body);
183→        return;
184→      }
185→
186→      const payload = (await response.json()) as WorkspaceConversationResponse;
187→      const uiMessages = bootstrapMessagesToUIMessages(payload.messages) as ChatUIMessage[];
188→      chat.setMessages(uiMessages);
189→
190→      setActiveConversationId(conversationId);
191→      conversationIdRef.current = conversationId;
192→      setConversationDiscussEntity(payload.discussEntity);
193→    } catch (error) {
194→      const messageText = error instanceof Error ? error.message : "Failed to load conversation";
195→      setErrorMessage(messageText);
196→    }
197→  }
198→
199→  const sendMessage = useCallback(
200→    (text: string, options?: { onboardingAction?: OnboardingAction }) => {
201→      if (isLoading || !workspaceId) return;
202→
203→      const trimmed = text.trim();
204→      if (!trimmed) return;
205→
206→      setErrorMessage(undefined);
207→      onboardingActionRef.current = options?.onboardingAction;
208→
209→      chat.sendMessage({ text: trimmed });
210→
211→      // Clear after queueing
212→      onboardingActionRef.current = undefined;
213→    },
214→    [isLoading, workspaceId, chat.sendMessage],
215→  );
216→
217→  function stopMessage() {
218→    chat.stop();
219→  }
220→
221→  function newConversation() {
222→    setActiveConversationId(undefined);
223→    conversationIdRef.current = undefined;
224→    chat.setMessages([]);
225→    setErrorMessage(undefined);
226→    setConversationDiscussEntity(undefined);
227→    clearDiscussEntity();
228→  }
229→
230→  function selectConversation(conversationId: string) {
231→    if (conversationId === activeConversationId || isLoading || !workspaceId) {
232→      return;
233→    }
234→    void loadConversation(workspaceId, conversationId);
235→  }
236→
237→  async function branchFromMessage(messageId: string) {
238→    if (!workspaceId || !activeConversationId || isLoading) return;
239→
240→    setBranchingFromId(messageId);
241→    try {
242→      const response = await fetch(
243→        `/api/workspaces/${encodeURIComponent(workspaceId)}/conversations/${encodeURIComponent(activeConversationId)}/branch`,
244→        {
245→          method: "POST",
246→          headers: { "Content-Type": "application/json" },
247→          body: JSON.stringify({ messageId }),
248→        },
249→      );
250→
251→      if (!response.ok) {
252→        const body = await response.text();
253→        setErrorMessage(body);
254→        return;
255→      }
256→
257→      const payload = (await response.json()) as BranchConversationResponse;
258→      await loadConversation(workspaceId, payload.conversationId);
259→      await refreshSidebar(workspaceId);
260→    } catch (error) {
261→      const messageText = error instanceof Error ? error.message : "Branch creation failed";
262→      setErrorMessage(messageText);
263→    } finally {
264→      setBranchingFromId(undefined);
265→    }
266→  }
267→
268→  return {
269→    messages: chat.messages,
270→    status: chat.status,
271→    isLoading,
272→    errorMessage,
273→    activeConversationId,
274→    branchingFromId,
275→    discussEntity,
276→    conversationDiscussEntity,
277→    sendMessage,
278→    stopMessage,
279→    newConversation,
280→    selectConversation,
281→    branchFromMessage,
282→    setErrorMessage,
283→    refreshSidebar,
284→  };
285→}
