 82→    set({ seedItems: [...deduped.values()] });
 83→  },
 84→  setIsBootstrapping: (isBootstrapping) => set({ isBootstrapping }),
 85→  setSidebarHandlers: (sidebarHandlers) => set({ sidebarHandlers }),
