  1→import { tool } from "ai";
  2→import { z } from "zod";
  3→import { createEmbeddingVector } from "../../graph/embeddings";
  4→import {
  5→  parseRecordIdString,
  6→  readEntityName,
  7→  resolveWorkspaceProjectRecord,
  8→  searchConversationMessagesByEmbedding,
  9→  type GraphEntityRecord,
 10→} from "../../graph/queries";
 11→import { requireToolContext } from "./helpers";
 12→import type { ChatToolDeps } from "./types";
 13→
 14→export function createGetConversationHistoryTool(deps: ChatToolDeps) {
 15→  return tool({
 16→    description:
 17→      "Search past conversations for discussions about a topic and return relevant message excerpts with linked entities.",
 18→    inputSchema: z.object({
 19→      query: z.string().min(1).describe("Topic to search for"),
 20→      projectId: z.string().optional().describe("Optional project scope filter"),
 21→    }),
 22→    execute: async (input, options) => {
 23→      const context = requireToolContext(options);
 24→      const queryEmbedding = await createEmbeddingVector(deps.embeddingModel, input.query, deps.embeddingDimension);
 25→      if (!queryEmbedding) {
 26→        throw new Error("failed to create query embedding for get_conversation_history");
 27→      }
 28→
 29→      const projectRecord = input.projectId
 30→        ? await resolveWorkspaceProjectRecord({
 31→            surreal: deps.surreal,
 32→            workspaceRecord: context.workspaceRecord,
 33→            projectInput: input.projectId,
 34→          })
 35→        : undefined;
 36→
 37→      const messages = await searchConversationMessagesByEmbedding({
 38→        surreal: deps.surreal,
 39→        workspaceRecord: context.workspaceRecord,
 40→        queryEmbedding,
 41→        ...(projectRecord ? { projectRecord } : {}),
 42→        limit: 8,
 43→      });
 44→
 45→      const enrichedMessages = await Promise.all(
 46→        messages.map(async (message) => {
 47→          const messageRecord = parseRecordIdString(message.id, ["message"], "message");
 48→          const [entityRows] = await deps.surreal
 49→            .query<[Array<GraphEntityRecord>]>(
 50→              "SELECT VALUE out FROM extraction_relation WHERE `in` = $message LIMIT 8;",
 51→              { message: messageRecord },
 52→            )
 53→            .collect<[Array<GraphEntityRecord>]>() ;
 54→
 55→          const linkedEntities = await Promise.all(
 56→            entityRows.map(async (entityRecord) => {
 57→              const table = entityRecord.table.name;
 58→              if (
 59→                table !== "workspace" &&
 60→                table !== "project" &&
 61→                table !== "person" &&
 62→                table !== "feature" &&
 63→                table !== "task" &&
 64→                table !== "decision" &&
 65→                table !== "question"
 66→              ) {
 67→                return undefined;
 68→              }
 69→
 70→              const name = await readEntityName(deps.surreal, entityRecord);
 71→              if (!name) {
 72→                return undefined;
 73→              }
 74→
 75→              return {
 76→                id: `${table}:${entityRecord.id as string}`,
 77→                kind: table,
 78→                name,
 79→              };
 80→            }),
 81→          );
 82→
 83→          return {
 84→            messageId: `message:${message.id}`,
 85→            conversationId: `conversation:${message.conversationId}`,
 86→            excerpt: message.text.slice(0, 280),
 87→            confidence: Number(message.score.toFixed(4)),
 88→            linkedEntities: linkedEntities.filter((value) => value !== undefined),
 89→          };
 90→        }),
 91→      );
 92→
 93→      return {
 94→        query: input.query,
 95→        results: enrichedMessages,
 96→      };
 97→    },
 98→  });
 99→}
