236→async function resolveWorkspaceBootstrapConversation(
237→  deps: ServerDependencies,
238→  workspaceRecord: RecordId<"workspace", string>,
239→): Promise<RecordId<"conversation", string>> {
240→  const [onboardingRows] = await deps.surreal
241→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
242→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace AND source = 'onboarding' ORDER BY createdAt ASC LIMIT 1;",
243→      {
244→        workspace: workspaceRecord,
245→      },
246→    )
247→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
248→
249→  if (onboardingRows.length > 0) {
250→    return onboardingRows[0].id;
251→  }
252→
253→  const [latestRows] = await deps.surreal
254→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
255→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace ORDER BY createdAt DESC LIMIT 1;",
256→      {
257→        workspace: workspaceRecord,
258→      },
259→    )
260→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
261→
262→  if (latestRows.length > 0) {
263→    return latestRows[0].id;
264→  }
265→
266→  const now = new Date();
267→  const conversationRecord = new RecordId("conversation", randomUUID());
268→  await deps.surreal.create(conversationRecord).content({
269→    createdAt: now,
270→    updatedAt: now,
271→    workspace: workspaceRecord,
272→    source: "onboarding",
273→  });
274→  return conversationRecord;
275→}
