1186→          embedding?: number[];
1187→        }>,
1188→      ]>();
1189→
1190→    rows = messageRows;
1191→  } else {
1192→    const [messageRows] = await input.surreal
1193→      .query<[
1194→        Array<{
1195→          id: RecordId<"message", string>;
1196→          conversation: RecordId<"conversation", string>;
1197→          text: string;
1198→          createdAt: string | Date;
1199→          embedding?: number[];
1200→        }>,
1201→      ]>(
1202→        [
1203→          "SELECT id, conversation, text, createdAt, embedding",
1204→          "FROM message",
1205→          "WHERE embedding != NONE",
1206→          "AND conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
1207→          "ORDER BY createdAt DESC",
1208→          "LIMIT $limit;",
1209→        ].join(" "),
1210→        {
1211→          workspace: input.workspaceRecord,
1212→          limit: Math.max(input.limit * 25, 250),
1213→        },
1214→      )
1215→      .collect<[
1216→        Array<{
1217→          id: RecordId<"message", string>;
1218→          conversation: RecordId<"conversation", string>;
1219→          text: string;
1220→          createdAt: string | Date;
1221→          embedding?: number[];
1222→        }>,
1223→      ]>();
1224→
1225→    rows = messageRows;
1226→  }
1227→
1228→  const ranked = rows
1229→    .map((row) => ({
1230→      row,
1231→      score: row.embedding ? cosineSimilarity(input.queryEmbedding, row.embedding) : -1,
1232→    }))
1233→    .filter((row) => row.score > 0)
1234→    .sort((a, b) => b.score - a.score)
1235→    .slice(0, input.limit)
1236→    .map((item) => ({
1237→      id: toRecordIdString(item.row.id),
1238→      conversationId: toRecordIdString(item.row.conversation),
1239→      text: item.row.text,
1240→      score: item.score,
1241→      createdAt: toIsoString(item.row.createdAt),
1242→    } satisfies RankedMessage));
1243→
1244→  return ranked;
1245→}
