 35→/**
 36→ * Groups conversations by dominant project using strict majority heuristic.
 37→ * A conversation is assigned to a project only if that project's entity_count
 38→ * is strictly greater than half of the total entity count across all projects.
 39→ */
 40→export function groupConversationsByProject(conversations: ConversationGroupInput[]): GroupingResult {
 41→  const groups = new Map<string, ConversationSidebarItem[]>();
 42→  const unlinked: ConversationSidebarItem[] = [];
 43→
 44→  for (const conv of conversations) {
 45→    const item: ConversationSidebarItem = {
 46→      id: conv.id,
 47→      title: conv.title ?? "Untitled",
 48→      updatedAt: conv.updatedAt,
 49→    };
 50→
 51→    if (conv.touchedBy.length === 0) {
 52→      unlinked.push(item);
 53→      continue;
 54→    }
 55→
 56→    const total = conv.touchedBy.reduce((sum, edge) => sum + edge.entityCount, 0);
 57→    let topEdge = conv.touchedBy[0];
 58→    for (const edge of conv.touchedBy) {
 59→      if (edge.entityCount > topEdge.entityCount) {
 60→        topEdge = edge;
 61→      }
 62→    }
 63→
 64→    if (topEdge.entityCount > total / 2) {
 65→      const existing = groups.get(topEdge.projectId) ?? [];
 66→      existing.push(item);
 67→      groups.set(topEdge.projectId, existing);
 68→    } else {
 69→      unlinked.push(item);
 70→    }
 71→  }
 72→
 73→  return { groups, unlinked };
 74→}
