    status: chat.status,
    isLoading,
    errorMessage,
    activeConversationId,
    branchingFromId,
    discussEntity,
    conversationDiscussEntity,
    sendMessage,
    stopMessage,
    newConversation,
    selectConversation,
    branchFromMessage,
    setErrorMessage,
    refreshSidebar,
  };
